<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\Video;use Illuminate\Http\Request;class VideoController extends Controller{public function index(){$videos=Video::latest()->paginate(15);return view('admin.videos.index',compact('videos'));}public function create(){return view('admin.videos.form',['video'=>new Video]);}public function store(Request $r){Video::create($this->data($r));return redirect()->route('admin.videos.index')->with('success','Video saved.');}public function edit(Video $video){return view('admin.videos.form',compact('video'));}public function update(Request $r,Video $video){$video->update($this->data($r));return redirect()->route('admin.videos.index')->with('success','Video updated.');}private function data(Request $r){$d=$r->validate(['title'=>'required|max:191','youtube_url'=>'required|max:191','thumbnail'=>'nullable|max:191','placement'=>'required|max:50','sort_order'=>'nullable|integer']);$d['is_active']=$r->boolean('is_active');return $d;}}
